35: //go:generate mockery --name Provider --structname MockProvider --outpkg settingtest --filename provider_mock.go --output ./settingtest/
36: type Provider interface {
37: 	// Current returns a SettingsBag with a static copy of
38: 	// the current configured pairs of key/values for each
39: 	// configuration section.
40: 	Current() SettingsBag
41: 
42: 	CurrentVerbose() VerboseSettingsBag
43: 
44: 	// Update receives a SettingsBag with the pairs of key/values
45: 	// to be updated per section and a SettingsRemovals with the
46: 	// section keys to be removed.
47: 	Update(updates SettingsBag, removals SettingsRemovals) error
48: 	// KeyValue returns a key-value abstraction
49: 	// for the given pair of section and key.
50: 	KeyValue(section, key string) KeyValue
51: 	// Section returns a settings section
52: 	// abstraction for the given section name.
53: 	Section(section string) Section
54: 	// RegisterReloadHandler registers a handler for validation and reload
55: 	// of configuration updates tied to a specific section
56: 	RegisterReloadHandler(section string, handler ReloadHandler)
57: }
58: 
59: // Section is a settings section copy
60: // with all of its pairs of keys-values.
61: type Section interface {
62: 	// KeyValue returns a key-value
63: 	// abstraction for the given key.
64: 	KeyValue(key string) KeyValue
65: }
66: 
67: // KeyValue represents a settings key-value
68: // for a given pair of section and key.
69: type KeyValue interface {
70: 	// Key returns pair's key.
71: 	Key() string
72: 	// Value returns pair's value.
73: 	Value() string
74: 
75: 	// MustString returns the value's string representation
76: 	// If empty, then it returns the given default.
77: 	MustString(defaultVal string) string
78: 	// MustBool returns the value's boolean representation
79: 	// Otherwise returns the given default.
80: 	MustBool(defaultVal bool) bool
81: 	// MustDuration returns the value's time.Duration
82: 	// representation. Otherwise returns the given default.
83: 	MustDuration(defaultVal time.Duration) time.Duration
84: }
